import { execution } from '@dynatrace-sdk/automation-utils';
import { workflowsClient } from '@dynatrace-sdk/client-automation';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const timeFrameMs = parseInt(input.timeFrameMinutes) * 60 * 1000;
    const from = Date.now() - timeFrameMs;
    const to = Date.now();

    // Query executions
    const response = await workflowsClient.listExecutions({
      workflowId: input.workflowId || undefined,
      from: from,
      to: to,
      status: input.status || undefined,
      limit: parseInt(input.maxResults)
    });

    let executions = response.executions || [];

    // Apply sorting
    if (input.sortBy === 'duration') {
      executions.sort((a, b) => ((b.endTime || Date.now()) - b.startTime) - ((a.endTime || Date.now()) - a.startTime));
    } else if (input.sortBy === 'endTime') {
      executions.sort((a, b) => (b.endTime || 0) - (a.endTime || 0));
    } else {
      executions.sort((a, b) => b.startTime - a.startTime);
    }

    // Calculate statistics
    const stats = {
      total: executions.length,
      successful: executions.filter(e => e.status === 'SUCCESS').length,
      failed: executions.filter(e => e.status === 'FAILED').length,
      running: executions.filter(e => e.status === 'RUNNING').length
    };

    console.log(`Retrieved ${executions.length} execution records`);

    return {
      statistics: stats,
      successRate: `${((stats.successful / stats.total) * 100).toFixed(1)}%`,
      timeFrame: input.timeFrameMinutes,
      executions: executions.slice(0, parseInt(input.maxResults)).map(e => ({
        executionId: e.id,
        workflowId: e.workflowId,
        status: e.status,
        startTime: new Date(e.startTime).toISOString(),
        endTime: e.endTime ? new Date(e.endTime).toISOString() : null,
        duration: e.endTime ? e.endTime - e.startTime : null
      }))
    };
  } catch (error) {
    console.error('Error listing executions:', error);
    throw new Error(`Failed to list executions: ${error}`);
  }
}
